<?php
$pageTitle='CRM & Customers';
require_once dirname(__DIR__,2) . '/includes/functions.php';
erpGuard('crm');
$pdo=getDB();
$section=$_GET['section']??'leads';
if(isset($_GET['delete_lead'])){$stmt=$pdo->prepare('DELETE FROM ' . table('crm_leads') . ' WHERE id=?');$stmt->execute([(int)$_GET['delete_lead']]);flash('success','Lead deleted.');redirect(ADMIN_URL.'/erp/crm.php');}
if(isset($_GET['delete_customer'])){$stmt=$pdo->prepare('DELETE FROM ' . table('customers') . ' WHERE id=?');$stmt->execute([(int)$_GET['delete_customer']]);flash('success','Customer deleted.');redirect(ADMIN_URL.'/erp/crm.php?section=customers');}
if(isset($_GET['convert_lead'])){
  requireCustomerCreationAllowed($pdo);
  $stmt=$pdo->prepare('SELECT * FROM ' . table('crm_leads') . ' WHERE id=? LIMIT 1');$stmt->execute([(int)$_GET['convert_lead']]);$lead=$stmt->fetch();
  if($lead){
    $code='CUS-'.date('ymdHis').'-'.random_int(10,99);
    $stmt=$pdo->prepare('INSERT INTO ' . table('customers') . ' (customer_code,customer_type,company_name,contact_name,email,phone,status) VALUES (?,?,?,?,?,?,"active")');
    $stmt->execute([$code,$lead['customer_type']?:'b2c',$lead['company'],$lead['name'],$lead['email'],$lead['phone']]);
    $customerId=(int)$pdo->lastInsertId();
    $stmt=$pdo->prepare('UPDATE ' . table('crm_leads') . ' SET status="won",converted_customer_id=? WHERE id=?');$stmt->execute([$customerId,(int)$lead['id']]);
    logActivity($pdo,'CRM','lead_convert','Lead '.$lead['name'].' converted into customer record.','customer',$customerId);
    flash('success','Lead converted into a customer.');
  }
  redirect(ADMIN_URL.'/erp/crm.php?section=customers');
}
if($_SERVER['REQUEST_METHOD']==='POST'){
  if(($_POST['form_type']??'')==='lead'){
    $payload=[$_POST['name'],$_POST['email'],$_POST['phone'],$_POST['company'],$_POST['customer_type'],$_POST['status'],$_POST['source'],(float)$_POST['estimated_value'],(int)$_POST['probability'],$_POST['next_follow_up']?:null,(int)($_POST['assigned_to']??0),$_POST['notes']];
    if(!empty($_POST['id'])){$stmt=$pdo->prepare('UPDATE ' . table('crm_leads') . ' SET name=?,email=?,phone=?,company=?,customer_type=?,status=?,source=?,estimated_value=?,probability=?,next_follow_up=?,assigned_to=?,notes=? WHERE id=?');$stmt->execute([...$payload,(int)$_POST['id']]);flash('success','Lead updated.');}
    else{$stmt=$pdo->prepare('INSERT INTO ' . table('crm_leads') . ' (name,email,phone,company,customer_type,status,source,estimated_value,probability,next_follow_up,assigned_to,notes) VALUES (?,?,?,?,?,?,?,?,?,?,?,?)');$stmt->execute($payload);flash('success','Lead created.');}
    redirect(ADMIN_URL.'/erp/crm.php');
  }
  if(($_POST['form_type']??'')==='customer'){
    $payload=[$_POST['customer_code'],$_POST['customer_type'],$_POST['company_name'],$_POST['contact_name'],$_POST['email'],$_POST['phone'],$_POST['tax_number'],$_POST['billing_address'],$_POST['shipping_address'],(float)$_POST['credit_limit'],(int)$_POST['payment_terms_days'],$_POST['status']];
    if(!empty($_POST['id'])){$stmt=$pdo->prepare('UPDATE ' . table('customers') . ' SET customer_code=?,customer_type=?,company_name=?,contact_name=?,email=?,phone=?,tax_number=?,billing_address=?,shipping_address=?,credit_limit=?,payment_terms_days=?,status=? WHERE id=?');$stmt->execute([...$payload,(int)$_POST['id']]);flash('success','Customer updated.');}
    else{requireCustomerCreationAllowed($pdo);$stmt=$pdo->prepare('INSERT INTO ' . table('customers') . ' (customer_code,customer_type,company_name,contact_name,email,phone,tax_number,billing_address,shipping_address,credit_limit,payment_terms_days,status) VALUES (?,?,?,?,?,?,?,?,?,?,?,?)');$stmt->execute($payload);flash('success','Customer created.');}
    redirect(ADMIN_URL.'/erp/crm.php?section=customers');
  }
}
$editLead=null;if(isset($_GET['edit_lead'])){$stmt=$pdo->prepare('SELECT * FROM ' . table('crm_leads') . ' WHERE id=?');$stmt->execute([(int)$_GET['edit_lead']]);$editLead=$stmt->fetch();}
$editCustomer=null;if(isset($_GET['edit_customer'])){$stmt=$pdo->prepare('SELECT * FROM ' . table('customers') . ' WHERE id=?');$stmt->execute([(int)$_GET['edit_customer']]);$editCustomer=$stmt->fetch();$section='customers';}
$leads=$pdo->query('SELECT l.*,CONCAT(e.first_name," ",e.last_name) owner_name FROM ' . table('crm_leads') . ' l LEFT JOIN ' . table('employees') . ' e ON e.id=l.assigned_to ORDER BY l.created_at DESC')->fetchAll();
$customers=$pdo->query('SELECT c.*,COALESCE(SUM(i.total),0) invoiced_total,COALESCE(SUM(i.balance_due),0) open_balance FROM ' . table('customers') . ' c LEFT JOIN ' . table('invoices') . ' i ON i.customer_id=c.id GROUP BY c.id ORDER BY c.created_at DESC')->fetchAll();
$employees=$pdo->query('SELECT id,CONCAT(first_name," ",last_name) label FROM ' . table('employees') . ' WHERE status="active" ORDER BY first_name')->fetchAll();
$leadCount=count($leads);$pipeline=(float)$pdo->query('SELECT COALESCE(SUM(estimated_value*probability/100),0) FROM ' . table('crm_leads') . ' WHERE status NOT IN ("won","lost")')->fetchColumn();$customerCount=count($customers);$b2b=(int)$pdo->query('SELECT COUNT(*) FROM ' . table('customers') . ' WHERE customer_type="b2b"')->fetchColumn();
include dirname(__DIR__).'/header.php';
?>
<div class="card-admin p-4 mb-4"><div class="d-flex flex-wrap justify-content-between align-items-center gap-3"><div><div class="erp-kicker"><?php echo t('Accounting Core', 'المحاسبة الأساسية'); ?></div><h2 class="h5 mb-1">Finance transactions now post into double-entry journals.</h2><p class="text-secondary mb-0">Invoices, payments, and expenses automatically create accounting entries when processed.</p></div><div class="d-flex flex-wrap gap-2"><a class="btn btn-outline-dark" href="<?php echo esc(ADMIN_URL); ?>/erp/chart-of-accounts.php"><?php echo t('Chart of Accounts', 'دليل الحسابات'); ?></a><a class="btn btn-outline-primary" href="<?php echo esc(ADMIN_URL); ?>/erp/trial-balance.php"><?php echo t('Trial Balance', 'ميزان المراجعة'); ?></a><a class="btn btn-brand" href="<?php echo esc(ADMIN_URL); ?>/erp/create-journal-entry.php">New Journal</a></div></div></div>
<div class="row g-4 mb-4"><div class="col-md-3"><div class="card-admin p-4"><div class="erp-kicker">Leads</div><div class="metric"><?php echo $leadCount; ?></div></div></div><div class="col-md-3"><div class="card-admin p-4"><div class="erp-kicker">Weighted Pipeline</div><div class="metric"><?php echo money($pipeline); ?></div></div></div><div class="col-md-3"><div class="card-admin p-4"><div class="erp-kicker"><?php echo t('Customers', 'العملاء'); ?></div><div class="metric"><?php echo $customerCount; ?></div></div></div><div class="col-md-3"><div class="card-admin p-4"><div class="erp-kicker">B2B Accounts</div><div class="metric"><?php echo $b2b; ?></div></div></div></div>
<ul class="nav nav-pills mb-4"><li class="nav-item"><a class="nav-link <?php echo $section==='leads'?'active':''; ?>" href="<?php echo esc(ADMIN_URL); ?>/erp/crm.php">Leads & Pipeline</a></li><li class="nav-item"><a class="nav-link <?php echo $section==='customers'?'active':''; ?>" href="<?php echo esc(ADMIN_URL); ?>/erp/crm.php?section=customers">B2B/B2C Customers</a></li></ul>
<?php if($section==='leads'): ?>
<div class="row g-4"><div class="col-xl-4"><form method="post" class="card-admin p-4"><input type="hidden" name="form_type" value="lead"><?php if($editLead): ?><input type="hidden" name="id" value="<?php echo (int)$editLead['id']; ?>"><?php endif; ?><h2 class="h5"><?php echo $editLead?'Edit Lead':'Create Lead'; ?></h2><div class="mb-2"><input class="form-control" name="name" placeholder="Contact name" value="<?php echo esc($editLead['name']??''); ?>" required></div><div class="row g-2"><div class="col-md-6 mb-2"><input class="form-control" name="email" placeholder="Email" value="<?php echo esc($editLead['email']??''); ?>"></div><div class="col-md-6 mb-2"><input class="form-control" name="phone" placeholder="Phone" value="<?php echo esc($editLead['phone']??''); ?>"></div></div><div class="mb-2"><input class="form-control" name="company" placeholder="Company" value="<?php echo esc($editLead['company']??''); ?>"></div><div class="row g-2"><div class="col-md-6 mb-2"><select class="form-select" name="customer_type"><option value="b2b" <?php echo ($editLead['customer_type']??'b2b')==='b2b'?'selected':''; ?>>B2B</option><option value="b2c" <?php echo ($editLead['customer_type']??'')==='b2c'?'selected':''; ?>>B2C</option></select></div><div class="col-md-6 mb-2"><select class="form-select" name="status"><?php foreach(['new','contacted','qualified','proposal','won','lost'] as $status): ?><option <?php echo ($editLead['status']??'new')===$status?'selected':''; ?>><?php echo esc($status); ?></option><?php endforeach; ?></select></div></div><div class="row g-2"><div class="col-md-6 mb-2"><input class="form-control" name="source" placeholder="Source" value="<?php echo esc($editLead['source']??'manual'); ?>"></div><div class="col-md-6 mb-2"><select class="form-select" name="assigned_to"><option value="0">Unassigned</option><?php foreach($employees as $employee): ?><option value="<?php echo (int)$employee['id']; ?>" <?php echo (int)($editLead['assigned_to']??0)===(int)$employee['id']?'selected':''; ?>><?php echo esc($employee['label']); ?></option><?php endforeach; ?></select></div></div><div class="row g-2"><div class="col-md-4 mb-2"><input class="form-control" type="number" step="0.01" name="estimated_value" placeholder="Value" value="<?php echo esc($editLead['estimated_value']??0); ?>"></div><div class="col-md-4 mb-2"><input class="form-control" type="number" min="0" max="100" name="probability" placeholder="Probability" value="<?php echo esc($editLead['probability']??0); ?>"></div><div class="col-md-4 mb-2"><input class="form-control" type="date" name="next_follow_up" value="<?php echo esc($editLead['next_follow_up']??''); ?>"></div></div><div class="mb-3"><textarea class="form-control" name="notes" rows="3" placeholder="Notes"><?php echo esc($editLead['notes']??''); ?></textarea></div><button class="btn btn-brand">Save Lead</button></form></div><div class="col-xl-8"><div class="table-wrap table-responsive"><table class="table"><thead><tr><th>Lead</th><th>Type</th><th>Stage</th><th>Pipeline</th><th>Next Follow-Up</th><th></th></tr></thead><tbody><?php foreach($leads as $lead): ?><tr><td><div class="fw-semibold"><?php echo esc($lead['name']); ?></div><div class="small-muted"><?php echo esc($lead['company']); ?> · <?php echo esc($lead['owner_name']?:'Unassigned'); ?></div></td><td><span class="badge <?php echo $lead['customer_type']==='b2b'?'badge-b2b':'badge-b2c'; ?>"><?php echo strtoupper(esc($lead['customer_type'])); ?></span></td><td><?php echo esc($lead['status']); ?></td><td><?php echo money($lead['estimated_value']); ?><div class="lead-progress mt-1"><span style="width:<?php echo max(0,min(100,(int)$lead['probability'])); ?>%"></span></div><div class="small-muted"><?php echo (int)$lead['probability']; ?>%</div></td><td><?php echo esc($lead['next_follow_up']); ?></td><td class="text-end"><a class="btn btn-outline-primary btn-sm" href="?edit_lead=<?php echo (int)$lead['id']; ?>">Edit</a> <?php if(!$lead['converted_customer_id']): ?><a class="btn btn-outline-success btn-sm" data-confirm="Convert this lead into a customer?" href="?convert_lead=<?php echo (int)$lead['id']; ?>">Convert</a><?php endif; ?> <a class="btn btn-outline-danger btn-sm" data-confirm="Delete lead?" href="?delete_lead=<?php echo (int)$lead['id']; ?>">Delete</a></td></tr><?php endforeach; ?></tbody></table></div></div></div>
<?php else: ?>
<div class="row g-4"><div class="col-xl-4"><form method="post" class="card-admin p-4"><input type="hidden" name="form_type" value="customer"><?php if($editCustomer): ?><input type="hidden" name="id" value="<?php echo (int)$editCustomer['id']; ?>"><?php endif; ?><h2 class="h5"><?php echo $editCustomer?'Edit Customer':'Create Customer'; ?></h2><div class="row g-2"><div class="col-md-6 mb-2"><input class="form-control" name="customer_code" placeholder="Customer code" value="<?php echo esc($editCustomer['customer_code']??('CUS-'.date('ymdHis'))); ?>" required></div><div class="col-md-6 mb-2"><select class="form-select" name="customer_type"><option value="b2b" <?php echo ($editCustomer['customer_type']??'b2b')==='b2b'?'selected':''; ?>>B2B</option><option value="b2c" <?php echo ($editCustomer['customer_type']??'')==='b2c'?'selected':''; ?>>B2C</option></select></div></div><div class="mb-2"><input class="form-control" name="company_name" placeholder="Company name" value="<?php echo esc($editCustomer['company_name']??''); ?>"></div><div class="mb-2"><input class="form-control" name="contact_name" placeholder="Contact name" value="<?php echo esc($editCustomer['contact_name']??''); ?>" required></div><div class="row g-2"><div class="col-md-6 mb-2"><input class="form-control" type="email" name="email" placeholder="Email" value="<?php echo esc($editCustomer['email']??''); ?>"></div><div class="col-md-6 mb-2"><input class="form-control" name="phone" placeholder="Phone" value="<?php echo esc($editCustomer['phone']??''); ?>"></div></div><div class="mb-2"><input class="form-control" name="tax_number" placeholder="Tax / TRN" value="<?php echo esc($editCustomer['tax_number']??''); ?>"></div><div class="mb-2"><textarea class="form-control" name="billing_address" rows="2" placeholder="Billing address"><?php echo esc($editCustomer['billing_address']??''); ?></textarea></div><div class="mb-2"><textarea class="form-control" name="shipping_address" rows="2" placeholder="Shipping address"><?php echo esc($editCustomer['shipping_address']??''); ?></textarea></div><div class="row g-2"><div class="col-md-6 mb-2"><input class="form-control" type="number" step="0.01" name="credit_limit" placeholder="Credit limit" value="<?php echo esc($editCustomer['credit_limit']??0); ?>"></div><div class="col-md-6 mb-2"><input class="form-control" type="number" name="payment_terms_days" placeholder="Terms days" value="<?php echo esc($editCustomer['payment_terms_days']??0); ?>"></div></div><div class="mb-3"><select class="form-select" name="status"><option <?php echo ($editCustomer['status']??'active')==='active'?'selected':''; ?>>active</option><option <?php echo ($editCustomer['status']??'')==='inactive'?'selected':''; ?>>inactive</option></select></div><button class="btn btn-brand">Save Customer</button></form></div><div class="col-xl-8"><div class="table-wrap table-responsive"><table class="table"><thead><tr><th>Customer</th><th>Type</th><th>Credit Terms</th><th>Invoiced</th><th>Open Balance</th><th></th></tr></thead><tbody><?php foreach($customers as $customer): ?><tr><td><div class="fw-semibold"><?php echo esc($customer['company_name']?:$customer['contact_name']); ?></div><div class="small-muted"><?php echo esc($customer['customer_code'].' · '.$customer['email']); ?></div></td><td><span class="badge <?php echo $customer['customer_type']==='b2b'?'badge-b2b':'badge-b2c'; ?>"><?php echo strtoupper(esc($customer['customer_type'])); ?></span></td><td><?php echo money($customer['credit_limit']); ?><div class="small-muted"><?php echo (int)$customer['payment_terms_days']; ?> days</div></td><td><?php echo money($customer['invoiced_total']); ?></td><td><?php echo money($customer['open_balance']); ?></td><td class="text-end"><a class="btn btn-outline-primary btn-sm" href="?section=customers&edit_customer=<?php echo (int)$customer['id']; ?>">Edit</a> <a class="btn btn-outline-danger btn-sm" data-confirm="Delete customer?" href="?section=customers&delete_customer=<?php echo (int)$customer['id']; ?>">Delete</a></td></tr><?php endforeach; ?></tbody></table></div></div></div>
<?php endif; ?>
<?php include dirname(__DIR__).'/footer.php'; ?>